package com.chaobo.scm.supplier.application.score;
import com.chaobo.scm.common.error.*;import com.chaobo.scm.supplier.application.integration.InboundEventPayloadStore;import com.chaobo.scm.supplier.application.masterdata.MasterDataEventConsumeLogPort;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.util.Set;
@Service public class PerformanceFactEventConsumerApplicationService{private static final String CONSUMER="supplier-performance-fact";private final MasterDataEventConsumeLogPort inbox;private final SupplierScoreApplicationService scores;private final InboundEventPayloadStore payloads;public PerformanceFactEventConsumerApplicationService(MasterDataEventConsumeLogPort inbox,SupplierScoreApplicationService scores,InboundEventPayloadStore payloads){this.inbox=inbox;this.scores=scores;this.payloads=payloads;}@Transactional public void consume(PerformanceFactEvent event){if(!Set.of("PURCHASE","WMS","TMS","BMS","SUPPLIER").contains(event.sourceSystem()))throw new BusinessException(ErrorCode.FORBIDDEN,"绩效事实来源不合法");var claim=inbox.claim(event.sourceSystem(),event.eventCode(),event.eventType(),CONSUMER,event.sourceSystem()+":"+event.eventCode());if(claim==MasterDataEventConsumeLogPort.ClaimResult.ALREADY_SUCCEEDED)return;if(claim==MasterDataEventConsumeLogPort.ClaimResult.IN_PROGRESS)throw new BusinessException(ErrorCode.IDEMPOTENCY_CONFLICT,"绩效事实正在处理");payloads.save(event.sourceSystem(),event.eventCode(),CONSUMER,event);try{scores.collectFact(event);inbox.markSucceeded(event.sourceSystem(),event.eventCode(),CONSUMER,false);}catch(RuntimeException exception){inbox.recordFailure(event.sourceSystem(),event.eventCode(),event.eventType(),CONSUMER,event.sourceSystem()+":"+event.eventCode(),exception.getMessage());throw exception;}}}
